mapper.select:
select id, project_id as projectId, name, plan_id as planId, content, stats_snapshot as statsSnapshot,
       create_time as createTime, update_time as updateTime, create_user as createUser, update_user as updateUser
from functional_test_report
where project_id = #{request.projectId}

    and name like concat('%', #{request.keyword}, '%')


    and plan_id = #{request.planId}
